{
    "level": "A2–B1",
    "intro": "W tym temacie nauczysz się <strong>poprawnie wybierać między comparative i superlative</strong> w zależności od kontekstu oraz liczby porównywanych elementów.",
    "rules": [
        {
            "label": "COMPARATIVE",
            "color": "blue",
            "text": "<strong>Porównanie dwóch rzeczy</strong> — zwykle z <em>than</em>:",
            "example": "This car is faster than that one."
        },
        {
            "label": "SUPERLATIVE",
            "color": "rose",
            "text": "<strong>Wyróżnienie jednego z grupy</strong> — zwykle z <em>the</em>:",
            "example": "This is the fastest car in the race."
        },
        {
            "label": "Różnica",
            "color": "emerald",
            "text": "<strong>Liczba elementów</strong> decyduje o wyborze:",
            "example": "2 elementy → comparative; 3+ → superlative"
        }
    ]
}

{
    "title": "1. Podstawowa różnica w użyciu",
    "intro": "Główna różnica między comparative i superlative polega na <strong>liczbie porównywanych elementów</strong>:",
    "rows": [
        {
            "en": "Comparative",
            "ua": "Stopień wyższy",
            "note": "Porównanie DWÓCH rzeczy lub osób → -er / more ... than"
        },
        {
            "en": "Superlative",
            "ua": "Stopień najwyższy",
            "note": "Wyróżnienie JEDNEGO elementu z grupy (3+) → -est / the most"
        },
        {
            "en": "Tom is taller than John.",
            "ua": "Tom jest wyższy od Johna.",
            "note": "✓ comparative — dwie osoby (Tom i John)"
        },
        {
            "en": "Tom is the tallest in the class.",
            "ua": "Tom jest najwyższy w klasie.",
            "note": "✓ superlative — jedna osoba z grupy (cała klasa)"
        }
    ],
    "warning": "💡 Zapamiętaj: <strong>dwa elementy = comparative</strong>, <strong>trzy lub więcej = superlative</strong>."
}

{
    "title": "2. Kiedy używać comparative",
    "sections": [
        {
            "label": "Dwa elementy",
            "color": "blue",
            "description": "Używaj <strong>comparative</strong>, gdy porównujesz <strong>dwie konkretne rzeczy</strong>:",
            "examples": [
                {
                    "en": "My house is bigger than your house.",
                    "ua": "Mój dom jest większy niż twój."
                },
                {
                    "en": "She is more intelligent than her brother.",
                    "ua": "Ona jest bardziej inteligentna niż jej brat."
                },
                {
                    "en": "Today is colder than yesterday.",
                    "ua": "Dziś jest zimniej niż wczoraj."
                }
            ]
        },
        {
            "label": "Porównanie z \"than\"",
            "color": "sky",
            "description": "Słowo <strong>than</strong> prawie zawsze wskazuje na comparative:",
            "examples": [
                {
                    "en": "This book is more interesting than the previous one.",
                    "ua": "Ta książka jest ciekawsza niż poprzednia."
                },
                {
                    "en": "He runs faster than anyone I know.",
                    "ua": "On biega szybciej niż ktokolwiek, kogo znam."
                },
                {
                    "en": "It's better than I expected.",
                    "ua": "To jest lepsze, niż się spodziewałem."
                }
            ]
        },
        {
            "label": "Porównanie domyślne",
            "color": "emerald",
            "description": "Nawet bez wyraźnego <strong>than</strong> używamy comparative, gdy zdanie sugeruje dwa stany lub dwie sytuacje:",
            "examples": [
                {
                    "en": "I feel better today. (than yesterday)",
                    "ua": "Dziś czuję się lepiej."
                },
                {
                    "en": "Can you speak louder? (than now)",
                    "ua": "Czy możesz mówić głośniej?"
                },
                {
                    "en": "This method is more effective. (than another one)",
                    "ua": "Ta metoda jest skuteczniejsza."
                }
            ]
        }
    ]
}

{
    "title": "3. Kiedy używać superlative",
    "sections": [
        {
            "label": "Wyróżnienie z grupy",
            "color": "rose",
            "description": "Używaj <strong>superlative</strong>, gdy wyróżniasz <strong>jeden element spośród wielu</strong>:",
            "examples": [
                {
                    "en": "He is the tallest student in the class.",
                    "ua": "On jest najwyższym uczniem w klasie."
                },
                {
                    "en": "This is the most expensive car in the showroom.",
                    "ua": "To jest najdroższy samochód w salonie."
                },
                {
                    "en": "She is the smartest person I know.",
                    "ua": "Ona jest najmądrzejszą osobą, jaką znam."
                }
            ]
        },
        {
            "label": "Użycie \"the\"",
            "color": "amber",
            "description": "Słowo <strong>the</strong> przed przymiotnikiem prawie zawsze sygnalizuje superlative:",
            "examples": [
                {
                    "en": "Mount Everest is the highest mountain in the world.",
                    "ua": "Mount Everest to najwyższa góra świata."
                },
                {
                    "en": "This is the best pizza I've ever had.",
                    "ua": "To najlepsza pizza, jaką kiedykolwiek jadłem."
                },
                {
                    "en": "She chose the cheapest option.",
                    "ua": "Wybrała najtańszą opcję."
                }
            ]
        },
        {
            "label": "Z in/of",
            "color": "sky",
            "description": "Superlative często łączy się z <strong>in</strong> (miejsce/grupa) albo <strong>of</strong> (zbiór):",
            "examples": [
                {
                    "en": "He is the fastest runner in the team.",
                    "ua": "On jest najszybszym biegaczem w drużynie."
                },
                {
                    "en": "This is the oldest of all the buildings.",
                    "ua": "To najstarszy ze wszystkich budynków."
                },
                {
                    "en": "She is the youngest in her family.",
                    "ua": "Ona jest najmłodsza w swojej rodzinie."
                }
            ]
        }
    ]
}

{
    "title": "4. Prosta zasada wyboru",
    "intro": "Krótki algorytm, który pomaga wybrać comparative albo superlative:",
    "items": [
        {
            "label": "Krok 1",
            "title": "Ile elementów porównujesz?",
            "subtitle": "2 elementy → Comparative; 3+ elementy → Superlative"
        },
        {
            "label": "Krok 2",
            "title": "Szukaj znaczników",
            "subtitle": "than = Comparative; the = Superlative"
        },
        {
            "label": "Krok 3",
            "title": "Sprawdź kontekst",
            "subtitle": "Bezpośrednie porównanie → Comparative; wyróżnienie jednego elementu → Superlative"
        },
        {
            "label": "Krok 4",
            "title": "Sprawdź przyimki",
            "subtitle": "in/of po przymiotniku → prawdopodobnie Superlative"
        }
    ]
}

{
    "title": "5. Porównanie konstrukcji",
    "intro": "Równoległe przykłady pomagające lepiej zobaczyć różnicę:",
    "rows": [
        {
            "en": "Paris is bigger than Lyon.",
            "ua": "Paryż jest większy niż Lyon.",
            "note": "✓ comparative — dwa miasta"
        },
        {
            "en": "Paris is the biggest city in France.",
            "ua": "Paryż jest największym miastem we Francji.",
            "note": "✓ superlative — jedno miasto spośród wielu"
        },
        {
            "en": "This exam was harder than the last one.",
            "ua": "Ten egzamin był trudniejszy niż poprzedni.",
            "note": "✓ comparative — dwa egzaminy"
        },
        {
            "en": "This was the hardest exam of the year.",
            "ua": "To był najtrudniejszy egzamin roku.",
            "note": "✓ superlative — jeden egzamin spośród wszystkich w danym roku"
        },
        {
            "en": "She is more experienced than me.",
            "ua": "Ona ma większe doświadczenie niż ja.",
            "note": "✓ comparative — dwie osoby"
        },
        {
            "en": "She is the most experienced in our team.",
            "ua": "Ona ma największe doświadczenie w naszym zespole."
            ,"note": "✓ superlative — jedna osoba w zespole"
        }
    ],
    "warning": "💡 Zwracaj uwagę na znaczniki: <strong>than</strong> dla comparative, <strong>the</strong> dla superlative."
}

{
    "title": "6. Typowe błędy",
    "sections": [
        {
            "label": "Błąd 1: mylenie \"the\"",
            "color": "rose",
            "description": "Używanie <strong>the</strong> z comparative albo pomijanie go przy superlative:",
            "examples": [
                {
                    "en": "❌ He is the taller than me. → ✓ He is taller than me.",
                    "ua": "Błąd: the przy comparative"
                },
                {
                    "en": "❌ She is most beautiful girl. → ✓ She is the most beautiful girl.",
                    "ua": "Błąd: brak the"
                },
                {
                    "en": "❌ This is more better. → ✓ This is better.",
                    "ua": "Błąd: podwójny znacznik"
                }
            ]
        },
        {
            "label": "Błąd 2: zły wybór formy",
            "color": "amber",
            "description": "Użycie comparative zamiast superlative i odwrotnie:",
            "examples": [
                {
                    "en": "❌ She is the taller of two sisters. → ✓ She is the taller of the two.",
                    "ua": "Przy dwóch elementach możliwy jest wzór: the taller of the two"
                },
                {
                    "en": "❌ He is taller in the class. → ✓ He is the tallest in the class.",
                    "ua": "Grupa wymaga superlative"
                },
                {
                    "en": "❌ This is the better than that. → ✓ This is better than that.",
                    "ua": "Bezpośrednie porównanie wymaga tylko comparative"
                }
            ]
        },
        {
            "label": "Błąd 3: brak \"than\"",
            "color": "sky",
            "description": "Pomijanie <strong>than</strong> po comparative w bezpośrednim porównaniu:",
            "examples": [
                {
                    "en": "❌ My car is faster your car. → ✓ My car is faster than yours.",
                    "ua": "Błąd: brak than"
                },
                {
                    "en": "❌ She is more intelligent him. → ✓ She is more intelligent than him.",
                    "ua": "Błąd: brak than"
                }
            ]
        }
    ]
}

{
    "title": "7. Szczególne przypadki",
    "sections": [
        {
            "label": "Dwa elementy",
            "color": "emerald",
            "description": "Z konstrukcją <strong>of the two</strong> angielski może użyć comparative z <strong>the</strong> dla podkreślenia:",
            "examples": [
                {
                    "en": "She is the taller of the two sisters.",
                    "ua": "Ona jest wyższą z dwóch sióstr."
                },
                {
                    "en": "She is taller than her sister.",
                    "ua": "Ona jest wyższa od swojej siostry."
                },
                {
                    "en": "This is the better of the two options.",
                    "ua": "To lepsza z dwóch opcji."
                }
            ]
        },
        {
            "label": "Zmiana stanu",
            "color": "blue",
            "description": "Comparative służy też do porównania <strong>różnych stanów tej samej rzeczy</strong>:",
            "examples": [
                {
                    "en": "The weather is getting colder.",
                    "ua": "Pogoda robi się chłodniejsza."
                },
                {
                    "en": "I'm feeling better now.",
                    "ua": "Teraz czuję się lepiej."
                },
                {
                    "en": "Life is more complicated than before.",
                    "ua": "Życie jest bardziej skomplikowane niż wcześniej."
                }
            ]
        },
        {
            "label": "Superlative absolutne",
            "color": "rose",
            "description": "Czasem superlative używa się <strong>bez podawania grupy</strong>, tylko dla podkreślenia:",
            "examples": [
                {
                    "en": "You are the best!",
                    "ua": "Jesteś najlepszy!"
                },
                {
                    "en": "This is the worst!",
                    "ua": "To jest najgorsze!"
                },
                {
                    "en": "Have a most wonderful day!",
                    "ua": "Życzę ci naprawdę cudownego dnia!"
                }
            ]
        }
    ]
}

{
    "title": "8. Lista kontrolna",
    "items": [
        {
            "label": "Sprawdzenie 1",
            "color": "emerald",
            "title": "Ile elementów porównujesz?",
            "wrong": "Dwa elementy?",
            "right": "→ Użyj <strong>comparative</strong>"
        },
        {
            "label": "Sprawdzenie 2",
            "color": "blue",
            "title": "Czy w zdaniu jest \"than\"?",
            "wrong": "Tak, jest \"than\"",
            "right": "→ Użyj <strong>comparative</strong>"
        },
        {
            "label": "Sprawdzenie 3",
            "color": "rose",
            "title": "Czy wyróżniasz jeden element z grupy?",
            "wrong": "Tak, jeden spośród wielu",
            "right": "→ Użyj <strong>the + superlative</strong>"
        },
        {
            "label": "Sprawdzenie 4",
            "color": "amber",
            "title": "Czy po przymiotniku występuje \"in/of\"?",
            "wrong": "Tak, jest in/of",
            "right": "→ Najpewniej chodzi o <strong>superlative</strong>"
        }
    ]
}
